class Solution {
public:
    int findLUSlength(string a, string b) {
        int n = a.length();
        int m = b.length();

        vector<vector<int>> dp(m + 1, vector<int>(n + 1, -1));

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                if (a[i - 1] == b[j - 1]) {
                    dp[j][i] = dp[j - 1][i - 1];
                } else {
                    dp[j][i] = max(dp[j][i - 1], dp[j - 1][i]);
                }
            }
        }

        return dp[m][n];
    }
};
